ps.pstext:
if !IsFeatureImplemented(FEAT_LSCP) then EndOfDecode(Decode_UNDEF); end;

let t : integer{} = UInt(Rt);
let t2 : integer{} = UInt(Rt2);
let n : integer{} = UInt(Rn);
let acquire : boolean = t != 31 && t2 != 31;
let tagchecked : boolean = n != 31;
let ispair : boolean = TRUE;
var rt_unknown : boolean = FALSE;

if t == t2 then
    let c : Constraint = ConstrainUnpredictable(Unpredictable_LDPOVERLAP);
    assert c IN {Constraint_UNKNOWN, Constraint_UNDEF, Constraint_NOP};
    case c of
        when Constraint_UNKNOWN =>    rt_unknown = TRUE;    // Result is UNKNOWN
        when Constraint_UNDEF =>      EndOfDecode(Decode_UNDEF);
        when Constraint_NOP =>        EndOfDecode(Decode_NOP);
    end;
end;

var address : bits(64);
var data1 : bits(64);
var data2 : bits(64);
let privileged : boolean = PSTATE.EL != EL0;

let accdesc : AccessDescriptor = CreateAccDescAcqRel(MemOp_LOAD, tagchecked, ispair, acquire,
                                                        t, t2);

if n == 31 then
    CheckSPAlignment();
    address = SP{64}();
else
    address = X{64}(n);
end;

let full_data : bits(128) = Mem{128}(address, accdesc);
if BigEndian(accdesc.acctype) then
    data2 = full_data[63:0];
    data1 = full_data[127:64];
else
    data1 = full_data[63:0];
    data2 = full_data[127:64];
end;

if rt_unknown then
    data1 = ARBITRARY : bits(64);
    data2 = ARBITRARY : bits(64);
end;

X{64}(t) = data1;
X{64}(t2) = data2;
